#include "vm_config_parser.h"
#include <limits.h>
#include <errno.h>

/* Maximum reasonable length for a configuration line */
#define MAX_CONFIG_LINE_LENGTH 4096

int parse_vm_config(const char* config_line, struct vm_hardware_config* hw_config) {
    /* Validate input parameters */
    if (config_line == NULL || hw_config == NULL) {
        return -1;
    }

    /* Check for empty string */
    if (config_line[0] == '\0') {
        return -1;
    }

    /* Check for unreasonably long input to prevent potential issues */
    size_t len = strlen(config_line);
    if (len > MAX_CONFIG_LINE_LENGTH) {
        return -1;
    }

    /* Initialize hw_config to safe defaults */
    memset(hw_config, 0, sizeof(struct vm_hardware_config));

    /* Make a working copy of config_line (strtok modifies the string) */
    char* work_buf = (char*)malloc(len + 1);
    if (work_buf == NULL) {
        return -1;
    }
    memcpy(work_buf, config_line, len + 1);

    /* Track which fields have been found */
    int cpu_model_found = 0;
    int memory_mb_found = 0;
    int disk_path_found = 0;
    int network_adapter_found = 0;

    /* Parse key=value pairs separated by commas */
    char* token = strtok(work_buf, ",");

    while (token != NULL) {
        /* Find the '=' separator */
        char* eq = strchr(token, '=');
        if (eq == NULL || eq == token) {
            /* Malformed: no '=' found or empty key */
            free(work_buf);
            return -1;
        }

        /* Split into key and value */
        *eq = '\0';
        const char* key = token;
        const char* value = eq + 1;

        /* Check for empty value */
        if (*value == '\0') {
            free(work_buf);
            return -1;
        }

        /* Match key and store value */
        if (strcmp(key, "cpu_model") == 0) {
            size_t value_len = strlen(value);
            if (value_len >= sizeof(hw_config->cpu_model)) {
                free(work_buf);
                return -1; /* Value too long */
            }
            memcpy(hw_config->cpu_model, value, value_len + 1);
            cpu_model_found = 1;
        } else if (strcmp(key, "memory_mb") == 0) {
            char* endptr;
            errno = 0;
            long mem = strtol(value, &endptr, 10);
            /* Check for conversion errors: overflow, non-numeric chars, invalid range */
            if (errno == ERANGE || *endptr != '\0' || mem <= 0 || mem > INT_MAX) {
                free(work_buf);
                return -1; /* Invalid memory value */
            }
            hw_config->memory_mb = (int)mem;
            memory_mb_found = 1;
        } else if (strcmp(key, "disk_path") == 0) {
            size_t value_len = strlen(value);
            if (value_len >= sizeof(hw_config->disk_path)) {
                free(work_buf);
                return -1; /* Value too long */
            }
            memcpy(hw_config->disk_path, value, value_len + 1);
            disk_path_found = 1;
        } else if (strcmp(key, "network_adapter") == 0) {
            size_t value_len = strlen(value);
            if (value_len >= sizeof(hw_config->network_adapter)) {
                free(work_buf);
                return -1; /* Value too long */
            }
            memcpy(hw_config->network_adapter, value, value_len + 1);
            network_adapter_found = 1;
        }
        /* Unknown keys are silently ignored */

        token = strtok(NULL, ",");
    }

    free(work_buf);

    /* Check that all required fields were found */
    if (!cpu_model_found || !memory_mb_found || !disk_path_found || !network_adapter_found) {
        return -1;
    }

    return 0;
}
